const survivesToNextGeneration = (isAlive: boolean, neighborCount: number): boolean =>
  neighborCount === 3 || (neighborCount === 2 && isAlive);

const countLiveNeighbors = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      const entry = counts.get(k);
      if (entry) entry.count += 1;
      else counts.set(k, { cell: neighbor, count: 1 });
    }
  }
  return counts;
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = countLiveNeighbors(liveCells);

  const nextLiveCells: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survivesToNextGeneration(aliveKeys.has(k), count)) {
      nextLiveCells.push(cell);
    }
  }
  return nextLiveCells;
}
